class GlobalStateValue(typing.TypedDict):
    """Shape of global_state state key values"""
    lastAttestationId: bytes
    lastOlderThan: bytes
    _scope: bytes
    _identityVerificationHubV2: str

class SelfVerificationRootTestState:
    """Methods to access state for the current SelfVerificationRootTest app"""

    def __init__(self, app_client: algokit_utils.AppClient):
        self.app_client = app_client

    @property
    def global_state(
        self
    ) -> "_GlobalState":
            """Methods to access global_state for the current app"""
            return _GlobalState(self.app_client)

class _GlobalState:
    def __init__(self, app_client: algokit_utils.AppClient):
        self.app_client = app_client
        
        # Pre-generated mapping of value types to their struct classes
        self._struct_classes: dict[str, typing.Type[typing.Any]] = {}

    def get_all(self) -> GlobalStateValue:
        """Get all current keyed values from global_state state"""
        result = self.app_client.state.global_state.get_all()
        if not result:
            return typing.cast(GlobalStateValue, {})

        converted = {}
        for key, value in result.items():
            key_info = self.app_client.app_spec.state.keys.global_state.get(key)
            struct_class = self._struct_classes.get(key_info.value_type) if key_info else None
            converted[key] = (
                _init_dataclass(struct_class, value) if struct_class and isinstance(value, dict)
                else value
            )
        return typing.cast(GlobalStateValue, converted)

    @property
    def last_attestation_id(self) -> bytes:
        """Get the current value of the lastAttestationId key in global_state state"""
        value = self.app_client.state.global_state.get_value("lastAttestationId")
        if isinstance(value, dict) and "AVMBytes" in self._struct_classes:
            return _init_dataclass(self._struct_classes["AVMBytes"], value)  # type: ignore
        return typing.cast(bytes, value)

    @property
    def last_older_than(self) -> bytes:
        """Get the current value of the lastOlderThan key in global_state state"""
        value = self.app_client.state.global_state.get_value("lastOlderThan")
        if isinstance(value, dict) and "AVMBytes" in self._struct_classes:
            return _init_dataclass(self._struct_classes["AVMBytes"], value)  # type: ignore
        return typing.cast(bytes, value)

    @property
    def scope(self) -> bytes:
        """Get the current value of the _scope key in global_state state"""
        value = self.app_client.state.global_state.get_value("_scope")
        if isinstance(value, dict) and "AVMBytes" in self._struct_classes:
            return _init_dataclass(self._struct_classes["AVMBytes"], value)  # type: ignore
        return typing.cast(bytes, value)

    @property
    def identity_verification_hub_v2(self) -> str:
        """Get the current value of the _identityVerificationHubV2 key in global_state state"""
        value = self.app_client.state.global_state.get_value("_identityVerificationHubV2")
        if isinstance(value, dict) and "address" in self._struct_classes:
            return _init_dataclass(self._struct_classes["address"], value)  # type: ignore
        return typing.cast(str, value)

